function makeRng(baseSeed, entityId, tag, tsMs) {
    const key = String(baseSeed) + ':' + String(entityId) + ':' + String(tag) + ':' + String(tsMs);
    const seedHex = crypto.createHash('sha256').update(key).digest('hex').slice(0, 16);
    return seedrandom.alea(seedHex);
}
function uniform(rng, min, max) { return min + (max - min) * rng(); }
function normal(rng, mean, stddev) {
    let u = 0; let v = 0;
    while (u === 0) u = rng();
    while (v === 0) v = rng();
    const z = Math.sqrt(-2 * Math.log(u)) * Math.cos(2 * Math.PI * v);
    return mean + stddev * z;
}
function isWeekend(d) { const w = d.getUTCDay(); return w === 0 || w === 6; }

const HOURLY_MULT = [0.9, 0.85, 0.82, 0.83, 0.88, 0.95, 1.05, 1.15, 1.25, 1.1, 1.05, 1.0, 0.98, 0.95, 0.97, 1.02, 1.08, 1.2, 1.35, 1.4, 1.15, 1.05, 0.98, 0.93];

const DEFAULT_CFG = {
    feed_id: 'price-default',
    night_price: 0.08,
    morning_peak_price: 0.18,
    midday_price: 0.12,
    evening_peak_price: 0.22,
    evening_price: 0.14,
    weekend_discount_pct: 7.5,
    volatility_pct: 8.0,
    min_price: 0.01
};

function tariffType(hour) {
    if (hour < 6) return 'NIGHT';
    if (hour < 9) return 'MORNING_PEAK';
    if (hour < 17) return 'MIDDAY';
    if (hour < 20) return 'EVENING_PEAK';
    return 'EVENING';
}

function basePrice(hour, cfg) {
    const t = tariffType(hour);
    if (t === 'NIGHT') return cfg.night_price;
    if (t === 'MORNING_PEAK') return cfg.morning_peak_price;
    if (t === 'MIDDAY') return cfg.midday_price;
    if (t === 'EVENING_PEAK') return cfg.evening_peak_price;
    return cfg.evening_price;
}

function hourlyMultiplier(date) {
    const h = date.getUTCHours();
    const m = date.getUTCMinutes();
    const cur = HOURLY_MULT[h];
    const nxt = HOURLY_MULT[(h + 1) % 24];
    return cur + (nxt - cur) * (m / 60);
}

function generatePrice(payload) {
    const baseSeed = (typeof payload.base_seed === 'number') ? payload.base_seed : 12345;
    const entityId = payload.entity_id || 'price-default';
    const tsMs = (typeof payload.timestamp_ms === 'number') ? payload.timestamp_ms : 0;
    const isoTs = payload.timestamp || new Date(tsMs).toISOString();
    const cfg = Object.assign({}, DEFAULT_CFG, payload.config || {});
    const mode = payload.mode || 'normal';
    const date = new Date(isoTs);
    const rng = makeRng(baseSeed, entityId, 'price', tsMs);

    const hour = date.getUTCHours();
    const t = tariffType(hour);
    let p = basePrice(hour, cfg) * hourlyMultiplier(date);
    if (isWeekend(date)) p *= (1 - cfg.weekend_discount_pct / 100);
    let vol = cfg.volatility_pct;
    if (mode === 'event') vol *= 2;
    p *= (1 + normal(rng, 0, vol / 100));
    p = Math.max(p, cfg.min_price);

    return {
        timestamp: isoTs,
        feed_id: cfg.feed_id || entityId,
        price_eur_per_kwh: p,
        tariff_type: t
    };
}

msg.payload = generatePrice(msg.payload || {});
return msg;
